	int j = 0;

	int i = 0;

	int m = 0;


	while (mesg.length()!=0) {

	   m=0;

	   i = mesg.indexOf("<");


	   if (i!=-1) {

	     tempst.append(mesg.substring(0,i));


	   } 
	   else {  	
	    tempst.append(mesg.substring(0));
	    break;
       }


	   j = mesg.indexOf(">"); 


	   subst=mesg.substring(i,j+1); 

	   while (subst.startsWith(taglist[m])==false) {

	   	m++;

	   	if (m==taglist.length) 

