            } catch (MalformedURLException e) {

                System.out.println("Invalid URL '"+args[1]+"'");
                printSyntax();
                System.exit(1);
            }
        }


        if (argc==5) {
            try {
                MINCHAR = Integer.valueOf(args[2]).intValue();
            } catch (NumberFormatException e) {
                System.out.println("Invalid  range number value '"+args[2]+"'");
                printSyntax();
                System.exit(1);
