	    tempst.append(mesg.substring(0));
	    break;
       }


	   j = mesg.indexOf(">"); 


	   subst=mesg.substring(i,j+1); 

	   while (subst.startsWith(taglist[m])==false) {

	   	m++;

	   	if (m==taglist.length) 

